INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fe0f68c5-141a-4d97-acfc-bb3bf6b550b5',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ Idempotency — Designing Consumers That Survive Duplicate Jobs$escape$,
  $escape$BullMQ's first deduplication layer is the `jobId` option on `queue.add()`. If a job with that ID already exists in `waiting`, `active`, or `delayed` state, the new add is silently ignored — no duplicate processing. But once a job completes and is removed (default behavior), that ID is free again. Set `removeOnComplete: false` to keep completed job records and block re-adds at the queue level.

For consumer-side safety, your processor must also be idempotent. Use `job.id` as an idempotency key against a Redis SET or a DB unique constraint. Check before doing work, record after. If your job triggers an external side effect (payment, email), guard it with a distributed lock using `ioredis` or an idempotency record in Postgres before calling out.

Avoid relying on `job.attemptsMade === 0` as a dedup signal — retries increment that counter but the original side effect may have partially succeeded. Track completion state externally, keyed by `job.id`, and return early if already processed. This pattern survives worker crashes, Redis failovers, and upstream replay storms.$escape$,
  $escape$import { Queue, Worker } from 'bullmq';
import { redis } from './redis';

const queue = new Queue('notifications', { connection: redis });

// Deduplicate at ingestion — same jobId won't re-enter if still active/waiting
await queue.add('send-email', { userId: 42 }, {
  jobId: `email-verify-${userId}`,
  removeOnComplete: false, // keeps record so re-adds are blocked after completion
});

const worker = new Worker('notifications', async (job) => {
  const alreadyDone = await redis.get(`processed:${job.id}`);
  if (alreadyDone) return; // idempotent guard

  await sendEmail(job.data.userId);
  await redis.set(`processed:${job.id}`, '1', 'EX', 86400);
}, { connection: redis });$escape$,
