INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '43b4760d-5da7-468e-a7c2-5381fe8ccdbf',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ — Priorities, Rate Limiting, Repeatables, and Job Dependencies$escape$,
  $escape$BullMQ gives you fine-grained control over job execution through four orthogonal mechanisms. Job priorities (1–2,097,152, lower = higher priority) let critical work jump the queue without a separate queue. Rate limiting via `limiter: { max, duration }` on the Worker caps throughput at the worker level — useful for third-party API quotas. Repeatable jobs use a cron expression or fixed interval stored in a sorted set; only one schedule entry exists regardless of how many times you call `add()` with the same `repeat` config and `jobId`. Job dependencies via `parent` and `children` create a DAG: a Flow produces parent-child chains where the parent job only moves to active once all children complete. Children can themselves have children. Use `FlowProducer.add()` to define the tree in one atomic call. One gotcha: repeatable jobs with `removeOnComplete` set to `true` still persist the repeat key — you must call `queue.removeRepeatable()` explicitly to stop recurrence. Mixing priorities with flows works, but priority is evaluated per-queue, so child jobs in different queues won't inherit parent priority.$escape$,
  $escape$import { Queue, Worker, FlowProducer } from 'bullmq';

const queue = new Queue('jobs', { connection });

// Priority job — lower number = higher priority
await queue.add('critical-task', { userId: 1 }, { priority: 1 });
await queue.add('background-task', { userId: 2 }, { priority: 100 });

// Rate-limited worker: max 10 jobs per 1000ms
const worker = new Worker('jobs', processor, {
  connection,
  limiter: { max: 10, duration: 1000 },
});

// Repeatable job — runs every day at 9am UTC
await queue.add('daily-digest', {}, {
  repeat: { pattern: '0 9 * * *' },
  jobId: 'daily-digest',
});

// Flow: parent waits for both children to finish
const flow = new FlowProducer({ connection });
await flow.add({
  name: 'send-report',
  queueName: 'jobs',
  children: [
    { name: 'fetch-data', queueName: 'jobs', data: { source: 'db' } },
    { name: 'fetch-metrics', queueName: 'jobs', data: { source: 'redis' } },
  ],
});$escape$,
