INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02355ceb-d546-4f2b-86e7-f4831872591e',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ — Redis Lists, Sorted Sets, and Streams: What Actually Backs Your Queue$escape$,
  $escape$BullMQ stores jobs in Redis Lists (`bull:{name}:wait`, `bull:{name}:active`) using LPUSH/BRPOP — not pub/sub. Delayed and prioritized jobs live in Sorted Sets, scored by execution timestamp or priority value. This is why `queue.getDelayed()` returns jobs in precise schedule order.

For events, BullMQ deliberately chose Redis Streams over pub/sub (the approach Bull v3 used). Streams persist messages in `bull:{name}:events`, so a `QueueEvents` subscriber that restarts can replay missed completions, failures, and stalls — pub/sub would have silently dropped them.

The persistence trade-off: Lists and Sorted Sets survive Redis restarts only if AOF (`appendonly yes`) or RDB snapshots are enabled. BullMQ adds no WAL of its own — it fully delegates durability to Redis. For critical workloads, `appendfsync everysec` is the minimum safe setting.

`removeOnComplete` and `removeOnFail` control Sorted Set bloat. Setting them to `{ count: 1000 }` caps memory without losing all observability. Leaving both false on high-throughput queues causes unbounded growth in `bull:{name}:completed` and `bull:{name}:failed`.$escape$,
  $escape$import { Queue, QueueEvents } from 'bullmq';

const queue = new Queue('orders', { connection: redis });

// Streams-based event bus — replays missed events after reconnect
const queueEvents = new QueueEvents('orders', { connection: redis });
queueEvents.on('completed', ({ jobId, returnvalue }) => {
  console.log(`Job ${jobId} finished:`, returnvalue);
});

// Delayed job → Sorted Set (bull:orders:delayed), scored by run-at timestamp
await queue.add('invoice', { orderId: 42 }, {
  delay: 10_000,
  removeOnComplete: { count: 500 },  // cap completed Sorted Set
  removeOnFail:    { age: 86_400 },  // evict failed jobs after 24 h
});$escape$,
