INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1f29c521-800c-4bc8-939a-33f3cbc3b127',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ — Routing Keys, Acks, and Prefetch Without RabbitMQ's Complexity$escape$,
  $escape$BullMQ skips RabbitMQ's exchange/binding layer entirely — queues are addressed directly by name. Job names serve as routing keys: a single Worker on the `orders` queue can branch on `job.name` to replicate topic-exchange fan-out without extra infrastructure or bindings to maintain.

Acknowledgements are implicit and lock-guarded. When your Worker handler resolves, BullMQ internally calls `moveToCompleted`, holding a unique per-job token to prevent double-processing across distributed workers. Throwing rejects the job — it moves to `failed` or re-queues via `opts.attempts` + `backoff`. There is no manual `ack()`/`nack()` call; the resolved or rejected promise *is* the ack.

Prefetch maps directly to the `concurrency` option on `Worker`. Setting `concurrency: 5` means at most 5 jobs are active in-flight per worker process. Unlike RabbitMQ's channel-level prefetch, BullMQ's concurrency is scoped to the `Worker` instance — scale throughput by spawning additional processes, not by widening a single connection's window.$escape$,
  $escape$import { Queue, Worker } from 'bullmq';
import { connection } from './redis';

const queue = new Queue('orders', { connection });

// job.name acts as the routing key — no exchange layer needed
await queue.add('payment.process', { orderId: '123' });
await queue.add('payment.refund',  { orderId: '456' });

const worker = new Worker('orders', async (job) => {
  if (job.name === 'payment.process') return processPayment(job.data);
  if (job.name === 'payment.refund')  return processRefund(job.data);
  // resolving = ack; throwing = nack → retry or failed
}, {
  connection,
  concurrency: 5, // prefetch equivalent: max 5 jobs in-flight per worker
});$escape$,
