INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '22336912-7ef5-4372-ae02-8915779c8bf3',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ — Routing, Cron Scheduling, Result Access, and FlowProducer Chains$escape$,
  $escape$BullMQ handles task routing through named queues — workers bind to a specific queue via `new Worker('email-queue', processor)`, so routing is implicit in which `Queue` instance you call `.add()` on. There's no global routing config like Celery's `task_routes`; queue name IS the route.

For scheduling (Celery beat equivalent), BullMQ uses repeatable jobs. Pass `{ repeat: { pattern: '0 9 * * *' } }` directly in `queue.add()`. In BullMQ v5+, the scheduler is built into `Queue` itself — no separate `QueueScheduler` process needed.

Result backends are Redis-native. When a worker's processor resolves a value, BullMQ persists it automatically. Retrieve it with `queue.getJob(jobId)` and read `.returnvalue` — no separate backend configuration required unlike Celery's `CELERY_RESULT_BACKEND`.

For chaining, `FlowProducer` is the answer — and it's more powerful than Celery's `chain()`. You define a job DAG where children must complete before the parent runs. Parent jobs receive children's results via `job.getChildrenValues()`, enabling true pipeline composition across multiple queues.$escape$,
  $escape$import { Queue, Worker, FlowProducer } from 'bullmq';

const connection = { host: 'localhost', port: 6379 };
const queue = new Queue('data-pipeline', { connection });

// Repeatable job — Celery beat equivalent
await queue.add('hourly-sync', { source: 'db' }, {
  repeat: { pattern: '0 * * * *' }
});

// FlowProducer chain — Celery chain() equivalent
const flow = new FlowProducer({ connection });
const { job } = await flow.add({
  name: 'notify',
  queueName: 'notifications',
  children: [{
    name: 'transform',
    queueName: 'transforms',
    children: [{ name: 'fetch', data: { id: 42 }, queueName: 'data-pipeline' }]
  }]
});

// Result backend equivalent — read after completion
const completed = await queue.getJob(job.id);
console.log(completed?.returnvalue);$escape$,
  $escape$typescript$escape$,
