INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd24ba478-24ad-47bb-b958-0df7b7ca8b6e',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ Ordering — Partitioning Strategy for Sequential Job Processing$escape$,
  $escape$BullMQ doesn't guarantee ordering when `concurrency > 1` — multiple workers racing on the same queue will process jobs out of sequence. For strict ordered processing (per-user event streams, sequential file transforms, ledger operations), partition by a logical key into separate queues, each backed by a `Worker` with `concurrency: 1`.

At runtime, maintain a registry of queue/worker pairs keyed by your partition identifier (userId, tenantId, deviceId). When a job arrives, map it to a queue name like `stream:user-42`, add the job, and lazily spin up a `Worker` for that queue if one doesn't exist. Each worker sees only its own FIFO stream — no concurrency races, no reordering.

Watch out: this creates O(N) Redis list structures and O(N) in-process event loops. Cap your partition count or reuse workers across a bounded pool of queue names. For high-cardinality keys, use a consistent-hash ring to map many keys to a smaller set of ordered queues — but always validate those workers run at `concurrency: 1`. Never raise concurrency thinking rate limiting will preserve order; it won't.$escape$,
  $escape$import { Queue, Worker } from 'bullmq';
import { redisConnection } from './redis';

const queues = new Map<string, Queue>();
const workers = new Map<string, Worker>();

function getOrCreatePartition(partitionKey: string) {
  const name = `ordered:${partitionKey}`;
  if (!workers.has(name)) {
    queues.set(name, new Queue(name, { connection: redisConnection }));
    workers.set(name, new Worker(name, async (job) => processJob(job), {
      connection: redisConnection,
      concurrency: 1,          // strict FIFO within this partition
    }));
  }
  return queues.get(name)!;
}

export async function enqueueOrdered(partitionKey: string, data: unknown) {
  const queue = getOrCreatePartition(partitionKey);
  await queue.add('task', data);
}$escape$,
