INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c6060712-3f75-4679-bf34-4951fd106fd2',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ vs NATS JetStream — Subject Routing and At-Least-Once Delivery Mapped$escape$,
  $escape$NATS JetStream offers subject-based routing (`orders.>`, `payments.*`) and durable at-least-once delivery. BullMQ provides equivalent guarantees through different primitives worth understanding side-by-side.

In BullMQ, queue names act as your top-level subject namespace, and job names provide the fine-grained routing JetStream subjects give you. A single Worker processes a queue but branches on `job.name` — no separate queue per event type required.

At-least-once delivery in JetStream hinges on explicit `ack()` calls within `ackWait`. BullMQ maps this to `lockDuration`: a Worker holds a Redis lock on the job for that window. If the worker crashes or stalls beyond `lockDuration`, the stalled-job checker (running every `stalledInterval` ms) re-queues the job automatically — up to `maxStalledCount` times before moving it to failed.

The critical difference: JetStream consumers can be push or pull; BullMQ is always pull — workers poll Redis. This means BullMQ won't saturate downstream services on burst traffic the way a push consumer can, but you lose JetStream's server-side fan-out to multiple consumer groups on a single subject stream.$escape$,
  $escape$import { Queue, Worker } from 'bullmq';

const queue = new Queue('orders.payments', { connection });

// Subject-like routing via job names
await queue.add('payment.captured', { orderId: '123' });
await queue.add('payment.refunded', { orderId: '456' });

const worker = new Worker('orders.payments', async (job) => {
  if (job.name === 'payment.captured') { /* handle capture */ }
  if (job.name === 'payment.refunded') { /* handle refund  */ }
}, {
  connection,
  lockDuration: 30_000,    // Equivalent to JetStream ackWait
  stalledInterval: 15_000, // Re-queue stalled (un-ACKed) jobs
  maxStalledCount: 2,      // Max redeliveries before → failed
});$escape$,
