INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '168c3d3a-d22f-479d-807b-3ef1c159a0d8',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ — Horizontal Worker Scaling, Locking, and Stall Recovery$escape$,
  $escape$Running multiple BullMQ `Worker` instances against the same queue is all you need for horizontal scaling — Redis handles coordination atomically. Each worker claims a job via a Lua script that moves it from the `wait` sorted set to `active` in one atomic operation, preventing double-processing without any external locking ceremony.

Throughput = worker instances × `concurrency`. The `concurrency` option (default: 1) sets parallel job slots per worker process. On I/O-heavy workloads, push it high — 20–50 is common. On CPU-bound work, keep it near core count.

BullMQ has no Kafka-style partitions to rebalance. All workers poll the same Redis key, so distribution is naturally load-balanced — an idle worker picks up the next available job immediately.

The critical tuning surface is `lockDuration` (default: 30 000 ms). A crashed worker releases its lock only after this window expires. Set `stalledInterval` to less than half of `lockDuration` so the stall checker catches orphaned jobs promptly. `maxStalledCount` (default: 1) controls how many stall cycles a job survives before being moved to `failed`. For long-running jobs, use `job.updateProgress()` — it also renews the lock, preventing false stalls.$escape$,
  $escape$import { Worker } from 'bullmq';
import { redisConnection } from './redis';

const worker = new Worker(
  'video-transcode',
  async (job) => {
    await transcode(job.data, (pct) => job.updateProgress(pct)); // renews lock
  },
  {
    connection: redisConnection,
    concurrency: 8,
    lockDuration: 60_000,    // 60s; must finish or renew within this window
    stalledInterval: 15_000, // scan for stalled jobs every 15s
    maxStalledCount: 2,      // move to failed after 2 stall cycles
  },
);$escape$,
  $escape$typescript$escape$,
