INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b8ce9e16-f519-43a6-9976-1ad19d855dec',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ Monitoring — Queue Depth Alerts, Consumer Lag, and Dead Letter Queues$escape$,
  $escape$BullMQ exposes rich observability via `Queue.getJobCounts()`, which returns active, waiting, failed, delayed, and paused counts in a single Redis call. Poll this on an interval and alert when `waiting` exceeds your SLA threshold or when `failed` crosses a noise floor. Consumer lag — the gap between job `timestamp` and `processedOn` — is available per-job via `Job.asJSON()` or in aggregate by comparing `Queue.getWaitingCount()` against worker throughput sampled over time. For dead-letter semantics, BullMQ has no built-in DLQ, but you can simulate one with `Worker`'s `failed` event: move exhausted jobs (where `job.attemptsMade >= job.opts.attempts`) to a dedicated `failed-jobs` queue using `failedQueue.add(job.name, job.data)`. Pair this with `QueueEvents` to receive `failed` and `stalled` events without polling. Set `stalledInterval` and `maxStalledCount` on the `Worker` to auto-recover or promote stalled jobs. Use `FlowProducer` job trees? Check parent job state via `Job.getDependenciesCount()` to detect dependency bottlenecks before the whole flow stalls.$escape$,
  $escape$import { Queue, Worker, QueueEvents } from 'bullmq';

const queue = new Queue('orders', { connection });
const events = new QueueEvents('orders', { connection });
const failedQueue = new Queue('orders-dlq', { connection });

// Queue depth alert
setInterval(async () => {
  const { waiting, failed } = await queue.getJobCounts();
  if (waiting > 500) alertOps(`Queue depth critical: ${waiting}`);
  if (failed > 50) alertOps(`Failed jobs spiking: ${failed}`);
}, 30_000);

// DLQ on exhausted retries
const worker = new Worker('orders', processor, {
  connection,
  stalledInterval: 15_000,
  maxStalledCount: 2,
});

worker.on('failed', async (job, err) => {
  if (job && job.attemptsMade >= (job.opts.attempts ?? 1)) {
    await failedQueue.add(job.name, { ...job.data, _error: err.message });
  }
});$escape$,
