INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '84a3bddd-a47d-44b4-83dc-44fb545db7e3',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ Security — Locking Down Redis Auth, TLS, and Network Isolation$escape$,
  $escape$BullMQ's entire attack surface is Redis. Every job payload, delay, and retry lives there — unprotected Redis means full queue compromise. Start with Redis 6+ ACL users: create a dedicated user with access scoped to only the key prefixes BullMQ uses (`bull:*`), not the default wildcard. Pass credentials via BullMQ's `connection` option, which proxies directly to ioredis. For TLS, set `tls: {}` inside the connection config — ioredis will negotiate TLS automatically; pair this with `rejectUnauthorized: true` to enforce cert validation against your CA. Never disable cert validation in production. For network isolation, Redis should never be publicly routable. In cloud environments, place it in a private subnet and use security groups or VPC peering to allow only your worker nodes' IPs. Use `RENAME_COMMAND` in `redis.conf` to obscure dangerous commands like `FLUSHALL` and `CONFIG`. BullMQ workers reconnect automatically on drop, so TLS handshake overhead is negligible after the initial connection pool warms up.$escape$,
  $escape$import { Worker, Queue } from 'bullmq';
import { readFileSync } from 'fs';

const connection = {
  host: 'redis.internal',
  port: 6380,
  username: 'bullmq-worker',
  password: process.env.REDIS_PASSWORD,
  tls: {
    ca: readFileSync('/certs/ca.crt'),
    rejectUnauthorized: true,
  },
};

const queue = new Queue('jobs', { connection });
const worker = new Worker('jobs', async job => { /* ... */ }, { connection });$escape$,
