INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1faedd6-58af-4c59-8a62-7ad467b4eded',
  '00000000-0000-0000-0000-000000000001',
  $escape$BullMQ Decision Framework — When Redis Beats Kafka and RabbitMQ$escape$,
  $escape$BullMQ is the right tool when your workload fits the Redis job model: discrete tasks with retries, priorities, scheduling, and state. If you need delayed execution (`opts.delay`), rate-limited workers (`opts.limiter`), or parent-child job orchestration via `FlowProducer`, BullMQ delivers with zero extra infrastructure beyond Redis.

Reach for Kafka when you need durable, replayable event streams. BullMQ jobs are consumed once — there is no `seekToOffset`, no consumer group offset management. If multiple independent services need the same events at different replay positions (audit logs, event sourcing), Kafka is the right fit.

RabbitMQ wins when broker-side routing topology matters: topic exchanges, fanout bindings, or `x-dead-letter-exchange` configurations that BullMQ can't replicate. BullMQ's `moveToFailed` and `getFailedJobs()` handle dead-letter scenarios, but the routing logic lives in your worker code, not the broker.

The rule: already on Redis and need task orchestration with retries, flows, and scheduling — use BullMQ. Need event replay across independent consumers — Kafka. Need complex broker-side routing or AMQP protocol compatibility — RabbitMQ.$escape$,
  $escape$import { FlowProducer } from 'bullmq';

const flow = new FlowProducer({ connection: { host: 'localhost', port: 6379 } });

// Parent job runs only after ALL children complete.
// No equivalent primitive exists in Kafka or RabbitMQ.
await flow.add({
  name: 'send-weekly-report',
  queueName: 'reports',
  children: [
    { name: 'fetch-metrics', queueName: 'data', data: { range: '7d' } },
    { name: 'fetch-active-users', queueName: 'data', data: { active: true } },
  ],
});$escape$,
